import React, { useState, useEffect, useRef } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isUserDropdownOpen, setIsUserDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsUserDropdownOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  return (
    <nav className="bg-white shadow-md">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          {/* Logo and Brand */}
          <div className="flex items-center">
            <Link to="/" className="flex items-center space-x-3">
              <span className="material-symbols-outlined text-blue-600" style={{fontSize: '28px'}}>gavel</span>
              <div>
                <h1 className="font-bold text-xl tracking-tighter text-blue-600">CivicWatch</h1>
              </div>
            </Link>
          </div>

          {/* Desktop Navigation */}
          <div className="hidden md:flex items-center space-x-4">
            <Link
              to="/"
              className="font-body font-medium text-on-surface hover:text-primary transition-colors"
            >
              Home
            </Link>
            <Link
              to="/map"
              className="font-body font-medium text-on-surface hover:text-primary transition-colors"
            >
              Map View
            </Link>
            {user ? (
              <>
                <Link
                  to="/dashboard"
                  className="font-body font-medium text-on-surface hover:text-primary transition-colors"
                >
                  Dashboard
                </Link>
                <Link
                  to="/report-issue"
                  className="font-body font-medium text-on-surface hover:text-primary transition-colors"
                >
                  Report Issue
                </Link>
                {user.role === 'admin' && (
                  <Link
                    to="/admin"
                    className="font-body font-medium text-primary hover:text-primary/80 transition-colors"
                  >
                    Admin
                  </Link>
                )}
                <div className="flex items-center space-x-3 ml-4 pl-4 border-l border-outline-variant">
                  {/* User Profile Logo */}
                  <div className="relative" ref={dropdownRef}>
                    <button
                      onClick={() => setIsUserDropdownOpen(!isUserDropdownOpen)}
                      className="w-10 h-10 bg-primary-container rounded-full flex items-center justify-center hover:bg-primary-container/80 transition-colors focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2"
                    >
                      <span className="material-symbols-outlined text-primary">account_circle</span>
                    </button>
                    {/* User Dropdown Menu */}
                    {isUserDropdownOpen && (
                      <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-lg border border-gray-200 py-2 z-50">
                        <div className="px-4 py-2 border-b border-gray-200">
                          <div className="text-sm font-medium text-gray-900">{user.name}</div>
                          <div className="text-xs text-gray-500 capitalize">{user.role}</div>
                        </div>
                        <button
                          onClick={() => {
                            handleLogout();
                            setIsUserDropdownOpen(false);
                          }}
                          className="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 transition-colors"
                        >
                          <span className="material-symbols-outlined text-sm mr-2">logout</span>
                          Logout
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </>
            ) : (
              <>
                <Link
                  to="/login"
                  className="font-body font-medium text-on-surface hover:text-primary transition-colors"
                >
                  Login
                </Link>
                <Link
                  to="/register"
                  className="bg-secondary hover:bg-secondary/90 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
                >
                  Get Started
                </Link>
              </>
            )}
          </div>

          {/* Mobile menu button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="p-2 rounded-md hover:bg-surface-container-high transition-colors"
            >
              <span className="material-symbols-outlined text-on-surface">
                {isMobileMenuOpen ? 'close' : 'menu'}
              </span>
            </button>
          </div>
        </div>

        {/* Mobile Navigation */}
        {isMobileMenuOpen && (
          <div className="md:hidden border-t border-outline-variant">
            <div className="px-2 pt-2 pb-3 space-y-1">
              <Link
                to="/"
                className="block px-4 py-2 rounded-lg text-sm font-medium text-on-surface hover:bg-surface-container-high transition-colors"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                Home
              </Link>
              <Link
                to="/map"
                className="block px-4 py-2 rounded-lg text-sm font-medium text-on-surface hover:bg-surface-container-high transition-colors"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                Map View
              </Link>
              {user ? (
                <>
                  <Link
                    to="/dashboard"
                    className="block px-4 py-2 rounded-lg text-sm font-medium text-on-surface hover:bg-surface-container-high transition-colors"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    Dashboard
                  </Link>
                  <Link
                    to="/report-issue"
                    className="block px-4 py-2 rounded-lg text-sm font-medium text-on-surface hover:bg-surface-container-high transition-colors"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    Report Issue
                  </Link>
                  {user.role === 'admin' && (
                    <Link
                      to="/admin"
                      className="block px-4 py-2 rounded-lg text-sm font-medium text-primary hover:bg-surface-container-high transition-colors"
                      onClick={() => setIsMobileMenuOpen(false)}
                    >
                      Admin
                    </Link>
                  )}
                  <div className="border-t border-outline-variant pt-2 mt-2">
                    <div className="px-4 py-2 flex items-center space-x-3">
                      <div className="w-8 h-8 bg-primary-container rounded-full flex items-center justify-center">
                        <span className="material-symbols-outlined text-sm text-primary">account_circle</span>
                      </div>
                      <div>
                        <div className="text-sm font-medium text-on-surface">{user.name}</div>
                        <div className="text-xs text-on-surface-variant capitalize">{user.role}</div>
                      </div>
                    </div>
                    <button
                      onClick={handleLogout}
                      className="block w-full text-left px-4 py-2 text-sm text-error hover:bg-error-container hover:text-on-error-container transition-colors"
                    >
                      <span className="material-symbols-outlined text-sm mr-2">logout</span>
                      Logout
                    </button>
                  </div>
                </>
              ) : (
                <>
                  <Link
                    to="/login"
                    className="block px-4 py-2 rounded-lg text-sm font-medium text-on-surface hover:bg-surface-container-high transition-colors"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    Login
                  </Link>
                  <Link
                    to="/register"
                    className="block px-4 py-2 rounded-lg text-sm font-medium bg-secondary text-white hover:bg-secondary/90 transition-colors"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    Get Started
                  </Link>
                </>
              )}
            </div>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
